#include <iostream>

int compute(int a, int b)
{
    return a * b - a;
}

int main()
{
    int a;
    int b;
    std::cin >> a >> b;
    std::cerr << "[debug] a=" << a << " b=" << b << "\n";
    int result = compute(a, b);
    std::cerr << "[debug] result=" << result << "\n";
    std::cout << "Result: " << result << "\n";
    return 0;
}

